import React, { useState, useEffect } from 'react';
import {
  Paper,
  Typography,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Chip,
  Box,
  CircularProgress,
  Alert,
  IconButton,
  Tooltip,
  Fade,
  useTheme
} from '@mui/material';
import {
  Refresh,
  TrendingUp,
  TrendingDown,
  Schedule
} from '@mui/icons-material';
import dashboardService from '../../services/dashboardService';

const OpenPositions = () => {
  const [positions, setPositions] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [refreshing, setRefreshing] = useState(false);

  useEffect(() => {
    loadPositions();

    // Timer para atualização automática a cada 30 segundos
    const interval = setInterval(() => {
      loadPositions();
    }, 30000); // 30 segundos

    // Cleanup do timer quando o componente for desmontado
    return () => clearInterval(interval);
  }, []);

  const loadPositions = async () => {
    try {
      setLoading(true);
      setError('');
      const response = await dashboardService.getOpenPositions();

      if (response.success) {
        setPositions(response.data || []);
      } else {
        setError(response.message || 'Erro ao carregar posições');
      }
    } catch (error) {
      console.error('Erro ao carregar posições:', error);
      setError('Erro ao conectar com o servidor');
    } finally {
      setLoading(false);
    }
  };

  const handleRefresh = async () => {
    setRefreshing(true);
    await loadPositions();
    setRefreshing(false);
  };

  const formatCurrency = (value, currency = 'USDT') => {
    return `${parseFloat(value || 0).toFixed(4)} ${currency}`;
  };

  const formatPercentage = (value) => {
    const formatted = parseFloat(value || 0).toFixed(2);
    return `${formatted >= 0 ? '+' : ''}${formatted}%`;
  };

  const getColorByValue = (value) => {
    if (value > 0) return '#02c076'; // Verde
    if (value < 0) return '#f84960'; // Vermelho
    return '#848e9c'; // Cinza neutro
  };

  const getSideColor = (side) => {
    return side === 'long' ? '#02c076' : '#f84960';
  };

  const getSideIcon = (side) => {
    return side === 'long' ? <TrendingUp /> : <TrendingDown />;
  };

  if (loading) {
    return (
      <Paper sx={{ p: 3, textAlign: 'center' }}>
        <CircularProgress />
        <Typography variant="body2" sx={{ mt: 2 }}>
          Carregando posições...
        </Typography>
      </Paper>
    );
  }

  return (
    <Paper sx={{ p: 3 }}>
      <Box display="flex" justifyContent="space-between" alignItems="center" mb={2}>
        <Typography variant="h6" component="h2">
          📊 Posições Abertas
        </Typography>
        <Tooltip title="Atualizar">
          <IconButton 
            onClick={handleRefresh} 
            disabled={refreshing}
            size="small"
          >
            <Refresh sx={{ 
              animation: refreshing ? 'spin 1s linear infinite' : 'none',
              '@keyframes spin': {
                '0%': { transform: 'rotate(0deg)' },
                '100%': { transform: 'rotate(360deg)' }
              }
            }} />
          </IconButton>
        </Tooltip>
      </Box>

      {error && (
        <Alert severity="warning" sx={{ mb: 2 }}>
          {error}
        </Alert>
      )}

      {positions.length === 0 ? (
        <Box textAlign="center" py={4}>
          <Typography variant="body1" color="text.secondary">
            Nenhuma posição aberta
          </Typography>
        </Box>
      ) : (
        <TableContainer>
          <Table size="small">
            <TableHead>
              <TableRow>
                <TableCell>Par</TableCell>
                <TableCell>Lado</TableCell>
                <TableCell align="right">Tamanho</TableCell>
                <TableCell align="right">Alavancagem</TableCell>
                <TableCell align="right">Preço Entrada</TableCell>
                <TableCell align="right">Preço Atual</TableCell>
                <TableCell align="right">PnL</TableCell>
                <TableCell align="right">Margem</TableCell>
              </TableRow>
            </TableHead>
            <TableBody>
              {positions.map((position, index) => {
                const leverage = parseFloat(position.leverage) || 1;
                const pnlPercentage = position.entry_price > 0 
                  ? ((position.mark_price - position.entry_price) / position.entry_price * 100) * (position.side === 'long' ? 1 : -1) * leverage
                  : 0;

                return (
                  <TableRow key={index} hover>
                    <TableCell>
                      <Typography variant="body2" fontWeight="bold">
                        {position.symbol}
                      </Typography>
                    </TableCell>
                    <TableCell>
                      <Chip
                        icon={getSideIcon(position.side)}
                        label={position.side.toUpperCase()}
                        size="small"
                        sx={{
                          backgroundColor: getSideColor(position.side),
                          color: 'white',
                          fontWeight: 'bold'
                        }}
                      />
                    </TableCell>
                    <TableCell align="right">
                      <Typography variant="body2">
                        {formatCurrency(position.size, '')}
                      </Typography>
                    </TableCell>
                    <TableCell align="right">
                      <Typography variant="body2">
                        {position.leverage}x
                      </Typography>
                    </TableCell>
                    <TableCell align="right">
                      <Typography variant="body2">
                        ${parseFloat(position.entry_price || 0).toFixed(4)}
                      </Typography>
                    </TableCell>
                    <TableCell align="right">
                      <Typography variant="body2">
                        ${parseFloat(position.mark_price || 0).toFixed(4)}
                      </Typography>
                    </TableCell>
                    <TableCell align="right">
                      <Box>
                        <Typography 
                          variant="body2" 
                          sx={{ color: getColorByValue(position.unrealized_pnl) }}
                          fontWeight="bold"
                        >
                          {formatCurrency(position.unrealized_pnl)}
                        </Typography>
                        <Typography 
                          variant="caption" 
                          sx={{ color: getColorByValue(pnlPercentage) }}
                        >
                          {formatPercentage(pnlPercentage)}
                        </Typography>
                      </Box>
                    </TableCell>
                    <TableCell align="right">
                      <Typography variant="body2">
                        {formatCurrency(position.margin_size)}
                      </Typography>
                    </TableCell>
                  </TableRow>
                );
              })}
            </TableBody>
          </Table>
        </TableContainer>
      )}

      {positions.length > 0 && (
        <Box mt={2} textAlign="center">
          <Typography variant="caption" color="text.secondary">
            Total: {positions.length} posição{positions.length !== 1 ? 'ões' : ''}
          </Typography>
        </Box>
      )}
    </Paper>
  );
};

export default OpenPositions;
